import { Link } from 'react-router-dom';

const VendorDashboard = () => {
  // Mock data
  const dashboardData = {
    totalBookings: 124,
    totalRevenue: 2480,
    activeFacilities: 3,
    pendingRequests: 5,
    recentBookings: [
      {
        id: 1,
        customerName: 'John Doe',
        facilityName: 'Badminton Court A',
        date: '2024-04-15',
        timeSlot: '5:00 PM - 7:00 PM',
        status: 'Confirmed',
      },
      {
        id: 2,
        customerName: 'Jane Smith',
        facilityName: 'Futsal Arena',
        date: '2024-04-16',
        timeSlot: '2:00 PM - 4:00 PM',
        status: 'Pending',
      },
      {
        id: 3,
        customerName: 'Mike Johnson',
        facilityName: 'Basketball Court 1',
        date: '2024-04-17',
        timeSlot: '6:00 PM - 8:00 PM',
        status: 'Confirmed',
      },
      {
        id: 4,
        customerName: 'Sarah Wilson',
        facilityName: 'Squash Room B',
        date: '2024-04-18',
        timeSlot: '10:00 AM - 12:00 PM',
        status: 'Confirmed',
      },
      {
        id: 5,
        customerName: 'Tom Brown',
        facilityName: 'Badminton Court B',
        date: '2024-04-19',
        timeSlot: '4:00 PM - 6:00 PM',
        status: 'Pending',
      },
    ],
  };

  const stats = [
    {
      title: 'Total Bookings',
      value: dashboardData.totalBookings,
      bgColor: 'bg-blue-50',
      textColor: 'text-blue-600',
    },
    {
      title: 'Total Revenue',
      value: `$${dashboardData.totalRevenue}`,
      bgColor: 'bg-green-50',
      textColor: 'text-green-600',
    },
    {
      title: 'Active Facilities',
      value: dashboardData.activeFacilities,
      bgColor: 'bg-purple-50',
      textColor: 'text-purple-600',
    },
    {
      title: 'Pending Requests',
      value: dashboardData.pendingRequests,
      bgColor: 'bg-red-50',
      textColor: 'text-red-600',
    },
  ];

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold mb-6">Vendor Dashboard</h1>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {stats.map((stat, index) => (
          <div
            key={index}
            className={`${stat.bgColor} p-6 rounded-lg shadow-sm border`}
          >
            <h3 className="text-sm font-medium text-gray-600 mb-2">{stat.title}</h3>
            <p className={`text-3xl font-bold ${stat.textColor}`}>{stat.value}</p>
          </div>
        ))}
      </div>

      {/* Manage Facilities Button */}
      <div className="mb-6">
        <Link
          to="/vendor/my-facilities"
          className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-lg transition-colors"
        >
          Manage My Facilities
        </Link>
      </div>

      {/* Recent Bookings Table */}
      <div className="bg-white rounded-lg shadow-sm border overflow-hidden">
        <div className="px-6 py-4 border-b">
          <h2 className="text-xl font-semibold">Recent Bookings</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Customer Name
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Facility Name
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Date
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Time Slot
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {dashboardData.recentBookings.map((booking) => (
                <tr key={booking.id}>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                    {booking.customerName}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {booking.facilityName}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {booking.date}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {booking.timeSlot}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span
                      className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full ${
                        booking.status === 'Confirmed'
                          ? 'bg-green-100 text-green-800'
                          : 'bg-yellow-100 text-yellow-800'
                      }`}
                    >
                      {booking.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default VendorDashboard;
